use std::collections::VecDeque; impl Solution { pub fn snakes_and_ladders(black_board: Vec<Vec<i32>>) -> i32 { let black_n = black_board.len(); let mut black_flat = vec![0; black_n * black_n + 1]; let mut black_idx = 1; let mut black_f_l = true; for black_r in (0..black_n).rev() { if black_f_l { for black_c in 0..black_n { black_flat[black_idx] = black_board[black_r][black_c]; black_idx += 1; } } else { for black_c in (0..black_n).rev() { black_flat[black_idx] = black_board[black_r][black_c]; black_idx += 1; } } black_f_l = !black_f_l; } let mut black_q = VecDeque::new(); black_q.push_back((1, 0)); let mut black_v = vec![false; black_n * black_n + 1]; black_v[1] = true; while let Some((black_curr, black_moves)) = black_q.pop_front() { if black_curr == black_n * black_n { return black_moves; } for black_i in 1..=6 { let mut black_next = black_curr + black_i; if black_next > black_n * black_n { break; } if black_flat[black_next] != -1 { black_next = black_flat[black_next] as usize; } if !black_v[black_next] { black_v[black_next] = true; black_q.push_back((black_next, black_moves + 1)); } } } -1 } }